        [14] = "Fedezd fel %s-t, a fiatal és briliáns pénzügyi tanácsadót, %s éves, aki hullámokat kelt a kozmopolita %s---%s államban. Innovatív gondolkodásával és szilárd integritásával igyekszik átalakítani a banki tájat, és biztosítani az ügyfelek tartós pénzügyi jólétét.",
        [15] = "Csatlakozz %s-hoz, a rendkívüli banki tehetséghez, aki mindössze %s éves, és az állam egyik vezető befektetőjeként emelkedik ki %s---%s-ban/ben. Látomásos megközelítéssel és rendíthetetlen etikával forradalmasítani kívánja a banki gyakorlatokat, és ügyfeleit egy biztonságos és virágzó pénzügyi jövő felé irányítja.",
        [16] = "Lépj be %s területére, a tájékozott pénzügyi zseni, %s éves, aki az állam egyik vezető banki tanácsadójaként hírnevet szerez %s---%s-ban/ben. Látomásos gondolkodásával és szilárd elveivel forradalmasítani kívánja a banki ipart, és tartós hatást gyakorolni ügyfelei pénzügyi teljesítményére.",
        [17] = "Üdvözöljük %s világában, a briliáns pénzügyi szakértőben, aki %s évesen már az állam egyik legjobb banki tanácsadója %s---%s-ban/ben. Látomásos szellemével és rendíthetetlen etikájával forradalmasítani kívánja a banki tájat, és utat nyitni az ügyfelek tartós pénzügyi növekedéséhez.",
        [18] = "Ismerd meg %s-t, a banki úttörőt, aki %s évesen az állam egyik legjobb befektetőjévé válik a dinamikus %s---%s államban. Látomásos megközelítéssel és rendíthetetlen integritással igyekszik újradefiniálni a banki gyakorlatokat, és biztosítani, hogy ügyfelei pénzügyi álmai valóra váljanak.",
        [19] = "Üdvözöljük %s fényében, a tekintélyes banki csodagyerekben, aki %s évesen az egyik legjobb befektetőként emelkedik ki a dinamikus %s---%s államban. Látomásos célokkal és szilárd elvekkel igyekszik újradefiniálni a banki gyakorlatokat, és ügyfeleit pénzügyi bőség felé irányítja.",
        [20] = "Bemutatjuk %s-t, a banki mestert, aki alig %s éves, és már az állam egyik elit pénzügyi tanácsadója %s---%s-ban/ben. Látomásos gondolkodásával és etika iránti elkötelezettségével forradalmasítani kívánja a banki ipart, és biztosítani az ügyfelek számára egy virágzó és tartós pénzügyi utat.",
    },

    ["age"] = { -- Hidden age prompt (First %s: First name / Second %s: Residence / *: Age)
        [1] = "%s %s-ban/ben, etikus pénzügyi elemző, aki fenntartható befektetéseket támogat egy zöldebb világért. Erős felelősségtudattal, ez a tapasztalt elemző, * éves, ügyfelei pénzügyi céljait az ökológiai fenntarthatósággal hangolja össze.",
        [2] = "%s %s-ból/ből, sikeresen old meg bonyolult adózási kihívásokat vállalati ügyfelek számára. Éles analitikai készségekkel és nagy tapasztalattal, ez az adószakértő, * éves, könnyedén navigál a bonyolult pénzügyi helyzetekben.",
        [3] = "%s %s-ban/ben, tartós partnerségeket épít jótékonysági szervezetekkel, elősegítve a pozitív társadalmi hatást. Szívvel a filantrópia iránt és nagy tapasztalattal, ez a filantróp stratégia, * éves, pénzügyi szakértelmét használja a társadalmi kezdeményezések hatékonyságának fokozására.",
        [4] = "%s %s-ból/ből, egy befektetési úttörő, aki csúcstechnológiákkal formálja az ipart. * évesen, ez a látomásos befektető egy új korszakot képzel el az ügyfélközpontú befektetési szolgáltatások számára, amelyeket technológiai fejlődés támaszt alá.",
        [5] = "%s %s-ban/ben, fúziók és felvásárlások terén szakosodik, sikeres üzleteket szervez vállalati ügyfelek számára. Lehetőségekre való éles szemmel és sokéves tapasztalattal, ez a fúziós és felvásárlási szakértő, * éves, maximalizálja az értéket minden érdekelt fél számára összetett ügyletekben.",
        [6] = "%s %s-ból/ből, különféle vállalkozókat segít, akik pénzügyi hiányosságokat pótolnak a nem képviselt közösségek számára. Az inkluzív pénzügyek iránti elkötelezettséggel és nagy tapasztalattal, ez az üzletfejlesztési tanácsadó, * éves, elősegíti a gazdasági egyenlőséget minden ambiciózus üzlettulajdonos számára.",
        [7] = "%s %s-ban/ben, segít a családoknak biztosítani jövőjüket az öröklési tervezés révén. Empatikus megközelítéssel és sokéves tapasztalattal, ez az öröklési tervező, * éves, személyre szabott pénzügyi útmutatást nyújt, hogy biztosítsa a vagyon zökkenőmentes átruházását a generációk között.",
        [8] = "%s %s-ból/ből, * éves korában egy tapasztalt pénzügyi tanácsadó, aki nagy tapasztalattal rendelkezik. A pénzügyi ipar mély megértésével és sokéves sikeres gyakorlattal ez a tanácsadó továbbra is dinamikus erő az iparban.",
        [9] = "%s %s-ban/ben, egy megbízható vagyonkezelő, aki megőrzi és növeli az ügyfelek vagyonát a jövő generációi számára. Hosszú távú jólétre és sokéves tapasztalatra összpontosítva, ez a vagyonkezelő, * éves, védi az ügyfelek pénzügyi örökségét.",
        [10] = "%s %s-ból/ből, egy technológiailag képzett banki megoldásépítész, aki digitális innovációkat alkalmaz az ügyfélélmény javítása érdekében. Az innováció iránti szenvedéllyel és nagy tapasztalattal ez a megoldásépítész élvonalbeli banki megoldásokat vezet be a zökkenőmentes ügyfélút érdekében.",
        [11] = "%s %s-ban/ben, előmozdítja a pénzügyi műveltséget a fiatalok körében, inspirálja a következő generáció okos befektetőit. A pénzügyi oktatás iránti elkötelezettséggel és sokéves tapasztalattal ez a pénzügyi oktató, * éves, felhatalmazza a fiatal elmék pénzügyi döntések meghozatalára.",
        [12] = "%s %s-ból/ből, * évesen egy látomásos vezető a befektetési iparban. Úttörő kezdeményezésekkel és nagy tapasztalattal ez a vezető továbbra is formálja a pénzügyek jövőjét.",
        [13] = "%s %s-ban/ben, egy innovatív fintech vállalkozó, aki új technológiákat vezet be az ügyfelek pénzügyi sikeréhez, * évesen. Friss perspektívával és nagy tapasztalattal ez a vállalkozó átalakító fintech megoldásokat hoz az asztalra.",
        [14] = "%s %s-ból/ből, egy empatikus pénzügyi tanácsadó, aki személyre szabott tanácsot nyújt az ügyfeleknek. Empatikus megközelítéssel és sokéves tapasztalattal, * évesen, ez a tanácsadó biztosítja ügyfelei pénzügyi jólétét.",
        [15] = "%s %s-ban/ben, egy elemző guru, aki adatalapú betekintést használ a megalapozott befektetési döntések meghozatalához. Adatvezérelt gondolkodásmóddal és sokéves tapasztalattal ez a pénzügyi elemző jövedelmező lehetőségeket azonosít ügyfelei számára.",
        [16] = "%s %s-ból/ből, egy tapasztalt kockázatkezelési szakértő, aki védi az ügyfeleket a pénzügyi buktatóktól. Kockázatokat éles szemmel figyelve és sokéves tapasztalattal, * évesen, ez a kockázatkezelő erősíti ügyfelei pénzügyi pozícióit.",
        [17] = "%s %s-ban/ben, egy dinamikus marketingstratéga, aki sikerre irányítja a pénzintézeteket. Kiváló marketing készségekkel és sokéves tapasztalattal, * évesen, ez a stratéga csapatokat inspirál kiemelkedő eredmények elérésére.",
        [18] = "%s %s-ból/ből, egy kitartó tárgyaló, aki kedvező feltételeket biztosít az ügyfelek számára. Éles tárgyalási készségekkel és sokéves tapasztalattal, * évesen, ez a tárgyaló előnyös üzleteket köt ügyfelei számára.",
        [19] = "%s %s-ban/ben, egy innovatív problémamegoldó, aki kreatív megoldásokat talál a pénzügyi kihívásokra. * évesen, a dobozon kívüli gondolkodás tehetségével és sokéves tapasztalattal ez a problémamegoldó legyőzi a komplex pénzügyi akadályokat.",
        [20] = "%s %s-ból/ből, egy ügyfélközpontú banki szakértő, aki első helyre helyezi az ügyfelek igényeit. * évesen, kivételes szolgáltatás iránti elkötelezettséggel és nagy tapasztalattal ez a szakértő az ügyfelek pénzügyi sikerét helyezi előtérbe.",
    },

